module top_module(/*AUTOARG*/
   // Inputs
   clk, rst, en,
   // Outputs
   count
   );// verilator coverage_off
   input clk, rst, en;
   output [3:0] count;
   // CHECK_COVER_MISSING(-1)

   reg [3:0] obf_count_reg;

   always @(posedge clk or negedge rst) begin
      if (~rst) begin
         obf_count_reg <= 4'b0;
      end else if (en) begin
         obf_count_reg <= obf_count_reg + 1;
      end
   end

   assign count = obf_count_reg;

endmodule
